@strawberry.type
class Query:
    @strawberry.field
    def products(self, info: Info, limit: int = 50, offset: int = 0) -> List[Product]:
        session: Session = info.context["session"]
        stmt = (
            select(ProductModel)
            .offset(offset)
            .limit(limit)
        )
        products = session.execute(stmt).scalars().all()
        return [Product(p) for p in products]

    @strawberry.field
    def product(self, info: Info, id: strawberry.ID) -> Optional[Product]:
        session: Session = info.context["session"]
        stmt = select(ProductModel).where(ProductModel.id == int(id))
        product = session.execute(stmt).scalars().first()
        return Product(product) if product else None


